using System;

public class OrderService
{
    public event EventHandler<string>? OrderShipped;

    public void ShipOrder(string orderId)
    {
        Console.WriteLine($"Shipping order {orderId}...");
        OrderShipped?.Invoke(this, orderId);
    }
}

class Program
{
    static void Main()
    {
        var service = new OrderService();

        service.OrderShipped += (s, orderId) =>
            Console.WriteLine($"Notification: Order {orderId} shipped!");

        service.OrderShipped += (s, orderId) =>
            Console.WriteLine($"Email sent for order {orderId}");

        service.ShipOrder("ORD-123");
    }
}
